import{_ as t,o as a,c as n,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Add Custom Partners","description":"","frontmatter":{"title":"Add Custom Partners","slug":"adding-custom-partners"},"headers":[],"relativePath":"marketer-hub/adding-custom-partners.md","filePath":"marketer-hub/adding-custom-partners.md"}'),o={name:"marketer-hub/adding-custom-partners.md"};function i(s,e,l,d,c,u){return a(),n("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms!</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>If you’re running an internal campaign or working with a new partner that does not have an official Branch integration, then you can manually set up the partner in Branch. Plus, first-time Branch users can find it helpful to create a custom test partner for the purposes of implementing the SDK or testing attribution initially.</p><p>Partners can fill out this <a href="https://branchmetrics.typeform.com/to/P9vQks?_branch_match_id=791705225390101698" target="_blank" rel="noreferrer">web form</a> to become an integrated partner.</p><h2 id="adding-a-custom-partner" tabindex="-1">Adding a Custom Partner <a class="header-anchor" href="#adding-a-custom-partner" aria-label="Permalink to &quot;Adding a Custom Partner&quot;">​</a></h2><p>To manually add a custom partner in your Branch dashboard:</p><ol><li>In the left-hand navigation, under <strong>Channels &amp; Links</strong>, click on <strong>Ads</strong> and then <strong>Partner Management</strong>.</li><li>On the <strong>Partner Management</strong> page, click <strong>+ Add Custom Partner</strong> on the bottom left.</li><li>In the <strong>Add New Custom Partner</strong> modal, provide a clearly identifiable name.</li><li>Click <strong>Save and Enable</strong>.</li></ol><h2 id="additional-setup" tabindex="-1">Additional Setup <a class="header-anchor" href="#additional-setup" aria-label="Permalink to &quot;Additional Setup&quot;">​</a></h2><p>To continue setting up your new custom partner, you can set up postback URLs and attribution windows. These are links used to measure ad displays and notify your partner of conversions, respectively.</p><h3 id="postback-configuration" tabindex="-1">Postback Configuration <a class="header-anchor" href="#postback-configuration" aria-label="Permalink to &quot;Postback Configuration&quot;">​</a></h3><ol><li>Click the <strong>Add New Postback</strong> button at the bottom of the screen.</li><li>A modal will appear with Branch default events, as well as any commerce or custom events you&#39;ve set up. Select an event, enter a postback URL if you&#39;re asked to, and click <strong>Save</strong>. This will be the event that triggers your new postback.</li></ol><div class="info custom-block"><p class="custom-block-title">Advanced Postback Configuration</p><p>For more information on Configuring Advanced Postbacks, view our guide <a href="./advanced-postback-configuration.html">here</a>.</p></div><h3 id="attribution-windows" tabindex="-1">Attribution Windows <a class="header-anchor" href="#attribution-windows" aria-label="Permalink to &quot;Attribution Windows&quot;">​</a></h3><p>You can edit your attribution windows at the partner level, if your partner requires it. This is recommended when you enable networks like Facebook and Google, who may have different windows for installs. With this, you can preserve your Account Level Attribution Windows, as well.</p>',14)])])}const m=t(o,[["render",i]]);export{p as __pageData,m as default};
